const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const articleTags = JSON.parse(localStorage.getItem('article_tags') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Find Wi-Fi Security tag
const wifiTag = tags.find(t => t && t.slug === 'wifi_security');
const wifiTagId = wifiTag ? wifiTag.id : null;

// Identify qualifying beginner Wi-Fi security articles
const qualifyingArticleIds = [];
if (wifiTagId) {
  for (let i = 0; i < articles.length; i++) {
    const a = articles[i];
    if (!a || a.category_id !== 'beginner') continue;
    if (typeof a.reading_time_minutes !== 'number' || a.reading_time_minutes > 8) continue;
    const year = a.published_at ? new Date(a.published_at).getUTCFullYear() : null;
    if (!year || year < 2023) continue;
    const hasWifiTag = articleTags.some(at => at && at.article_id === a.id && at.tag_id === wifiTagId);
    if (!hasWifiTag) continue;
    qualifyingArticleIds.push(a.id);
  }
}

// Find default Reading List collection
const defaultList = collections.find(c => c && c.is_default_reading_list);
let qualifyingBookmarkedCount = 0;
if (defaultList && qualifyingArticleIds.length > 0) {
  for (let i = 0; i < collectionItems.length; i++) {
    const ci = collectionItems[i];
    if (!ci || ci.collection_id !== defaultList.id) continue;
    if (qualifyingArticleIds.indexOf(ci.article_id) !== -1) {
      qualifyingBookmarkedCount++;
    }
  }
}

// Checkpoints reward ONLY correctly bookmarked qualifying articles
checkpoints.push({ passed: qualifyingBookmarkedCount >= 1, weight: 0.2 });
checkpoints.push({ passed: qualifyingBookmarkedCount >= 2, weight: 0.3 });
checkpoints.push({ passed: qualifyingBookmarkedCount >= 3, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const articleTags = JSON.parse(localStorage.getItem('article_tags') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Get tag IDs for VPN-related content
const vpnTagSlugs = ['vpn', 'vpn_setup'];
const vpnTagIds = tags
  .filter(t => t && vpnTagSlugs.indexOf(t.slug) !== -1)
  .map(t => t.id);

// Find VPN setup how-to guides (Guides / How-tos with VPN/VPN Setup tags)
const vpnGuides = articles.filter(a => {
  if (!a || a.content_type !== 'guides_how_tos') return false;
  const aTagIds = articleTags
    .filter(at => at && at.article_id === a.id)
    .map(at => at.tag_id);
  return vpnTagIds.some(id => aTagIds.indexOf(id) !== -1);
});

// Sort by most commented
vpnGuides.sort((a, b) => {
  const ca = typeof a.comment_count === 'number' ? a.comment_count : 0;
  const cb = typeof b.comment_count === 'number' ? b.comment_count : 0;
  return cb - ca;
});

const topTwo = vpnGuides.slice(0, 2);
const topTwoIds = topTwo.map(a => a.id);
const bestArticle = topTwo.length > 0 ? topTwo[0] : null;

// Find Practice Later collection
const practiceCollection = collections.find(c => c && (c.id === 'practice_later' || c.name === 'Practice Later'));
let bookmarkedInPracticeIds = [];
if (practiceCollection) {
  for (let i = 0; i < collectionItems.length; i++) {
    const ci = collectionItems[i];
    if (ci && ci.collection_id === practiceCollection.id) {
      bookmarkedInPracticeIds.push(ci.article_id);
    }
  }
}

const bookmarkedTop2Ids = topTwoIds.filter(id => bookmarkedInPracticeIds.indexOf(id) !== -1);

// CP1: User bookmarked at least one of the top-two most-commented VPN setup guides into Practice Later
checkpoints.push({ passed: topTwo.length > 0 && bookmarkedTop2Ids.length >= 1, weight: 0.4 });

// CP2: User bookmarked the MOST-commented guide among the top two into Practice Later
const cp2Passed = !!(bestArticle && bookmarkedInPracticeIds.indexOf(bestArticle.id) !== -1);
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const articleTags = JSON.parse(localStorage.getItem('article_tags') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Required tags: tools + account_security
const toolsTag = tags.find(t => t && t.slug === 'tools');
const acctSecTag = tags.find(t => t && t.slug === 'account_security');
const requiredTagIds = [];
if (toolsTag) requiredTagIds.push(toolsTag.id);
if (acctSecTag) requiredTagIds.push(acctSecTag.id);

function articleHasAllTags(articleId, tagIds) {
  const aTagIds = articleTags
    .filter(at => at && at.article_id === articleId)
    .map(at => at.tag_id);
  return tagIds.every(id => aTagIds.indexOf(id) !== -1);
}

// Candidate password manager review articles
const candidateArticles = articles.filter(a => {
  if (!a || a.content_type !== 'reviews') return false;
  const title = (a.title || '').toLowerCase();
  const hasPwdInTitle = title.indexOf('password manager') !== -1 || title.indexOf('password managers') !== -1;
  if (!hasPwdInTitle) return false;
  if (requiredTagIds.length > 0 && !articleHasAllTags(a.id, requiredTagIds)) return false;
  const tools = Array.isArray(a.recommended_tools) ? a.recommended_tools : [];
  return tools.length >= 3;
});

// Select article with the largest recommendation list
let bestArticle = null;
let maxTools = -1;
for (let i = 0; i < candidateArticles.length; i++) {
  const a = candidateArticles[i];
  const tools = Array.isArray(a.recommended_tools) ? a.recommended_tools : [];
  if (tools.length > maxTools) {
    maxTools = tools.length;
    bestArticle = a;
  }
}

// Find Research collection
const researchCollection = collections.find(c => c && (c.id === 'research' || c.name === 'Research'));
let researchArticleIds = [];
if (researchCollection) {
  for (let i = 0; i < collectionItems.length; i++) {
    const ci = collectionItems[i];
    if (ci && ci.collection_id === researchCollection.id) {
      researchArticleIds.push(ci.article_id);
    }
  }
}

// Articles in Research that meet the candidate criteria
const qualifyingInResearchCount = candidateArticles.filter(a => researchArticleIds.indexOf(a.id) !== -1).length;

// CP1: User saved at least one qualifying password manager review (correct tags and >=3 tools) into Research
checkpoints.push({ passed: qualifyingInResearchCount >= 1, weight: 0.4 });

// CP2: The review with the MOST recommended tools is in the Research collection
const cp2Passed = !!(bestArticle && researchArticleIds.indexOf(bestArticle.id) !== -1);
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const tags = JSON.parse(localStorage.getItem('tags') || '[]');
const articleTags = JSON.parse(localStorage.getItem('article_tags') || '[]');
const comments = JSON.parse(localStorage.getItem('article_comments') || '[]');
let clipboard = null;
try {
  clipboard = JSON.parse(localStorage.getItem('clipboardLastCopiedText') || 'null');
} catch (e) {
  clipboard = null;
}

// Find Phishing tag
const phishingTag = tags.find(t => t && t.slug === 'phishing');
const phishingTagId = phishingTag ? phishingTag.id : null;

function articleHasPhishing(articleId) {
  return articleTags.some(at => at && at.article_id === articleId && at.tag_id === phishingTagId);
}

// Qualifying phishing articles: tag=phishing, reading_time<=10, upvotes>=10
let qualifying = [];
if (phishingTagId) {
  qualifying = articles.filter(a => {
    if (!a) return false;
    if (!articleHasPhishing(a.id)) return false;
    if (typeof a.reading_time_minutes !== 'number' || a.reading_time_minutes > 10) return false;
    if (typeof a.upvotes !== 'number' || a.upvotes < 10) return false;
    return true;
  });
}

// Shortest by reading time (tie-breaker: earlier published_at)
qualifying.sort((a, b) => {
  const ra = typeof a.reading_time_minutes === 'number' ? a.reading_time_minutes : Number.MAX_SAFE_INTEGER;
  const rb = typeof b.reading_time_minutes === 'number' ? b.reading_time_minutes : Number.MAX_SAFE_INTEGER;
  if (ra !== rb) return ra - rb;
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return da - db;
});

const targetArticle = qualifying.length > 0 ? qualifying[0] : null;
let cp1Passed = false;
let cp2Passed = false;

if (targetArticle) {
  const expectedUrl = 'https://example.com/article.html?articleId=' + encodeURIComponent(targetArticle.id);
  cp1Passed = !!(clipboard && clipboard.text === expectedUrl);

  // New user comment: id starting with 'comment_' and content length >= 15
  const targetComments = comments.filter(c => c && c.article_id === targetArticle.id && !c.is_deleted);
  const newLongComments = targetComments.filter(c => {
    const isRuntimeId = typeof c.id === 'string' && c.id.indexOf('comment_') === 0;
    const lenOk = typeof c.content === 'string' && c.content.length >= 15;
    return isRuntimeId && lenOk;
  });
  cp2Passed = newLongComments.length > 0;
}

// CP1: User copied the link for the correct shortest qualifying phishing article
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2: User posted a new sufficiently long comment on that same article
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load notification settings
const notificationSettings = JSON.parse(localStorage.getItem('notification_settings') || '[]');

const osint = notificationSettings.find(s => s && s.topic === 'osint');
const malware = notificationSettings.find(s => s && s.topic === 'malware');

// CP1: OSINT set to on-site alerts, weekly
const cp1Passed = !!(osint && osint.delivery_type === 'on_site_alerts' && osint.frequency === 'weekly');
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2: Malware notifications disabled (delivery_type=disabled, frequency=none)
const cp2Passed = !!(malware && malware.delivery_type === 'disabled' && malware.frequency === 'none');
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Find candidate CTF write-ups: category=ctf_practice, difficulty=intermediate, challenge_year=2024, upvotes>=5
const candidates = articles.filter(a => {
  if (!a) return false;
  if (a.category_id !== 'ctf_practice') return false;
  if (a.difficulty !== 'intermediate') return false;
  if (typeof a.challenge_year !== 'number' || a.challenge_year !== 2024) return false;
  if (typeof a.upvotes !== 'number' || a.upvotes < 5) return false;
  return true;
});

// Newest by published_at
candidates.sort((a, b) => {
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return db - da;
});

const targetArticle = candidates.length > 0 ? candidates[0] : null;

// Find collections named 'Weekend Practice'
const weekendCollections = collections.filter(c => c && c.name === 'Weekend Practice');

let hasTargetInWeekend = false;
if (targetArticle && weekendCollections.length > 0) {
  for (let i = 0; i < weekendCollections.length; i++) {
    const col = weekendCollections[i];
    const foundItem = collectionItems.some(ci => ci && ci.collection_id === col.id && ci.article_id === targetArticle.id);
    if (foundItem) {
      hasTargetInWeekend = true;
      break;
    }
  }
}

// CP1: The correct newest qualifying CTF write-up is in a 'Weekend Practice' collection
checkpoints.push({ passed: !!(targetArticle && hasTargetInWeekend), weight: 0.5 });

// CP2: That article's reading_status is set to 'in_progress'
const cp2Passed = !!(targetArticle && targetArticle.reading_status === 'in_progress');
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load series and instrumentation
const seriesList = JSON.parse(localStorage.getItem('series') || '[]');
let seriesOpened = null;
let openedParts = null;
try {
  seriesOpened = JSON.parse(localStorage.getItem('task7_seriesOpened') || 'null');
} catch (e) {
  seriesOpened = null;
}
try {
  openedParts = JSON.parse(localStorage.getItem('task7_openedParts') || 'null');
} catch (e) {
  openedParts = null;
}

// Determine most popular Web Application Security series
const webAppSeries = seriesList.filter(s => s && s.topic === 'web_application_security');
webAppSeries.sort((a, b) => {
  const pa = typeof a.popularity_score === 'number' ? a.popularity_score : 0;
  const pb = typeof b.popularity_score === 'number' ? b.popularity_score : 0;
  return pb - pa;
});
const topSeries = webAppSeries.length > 0 ? webAppSeries[0] : null;

const partNumbers = openedParts && Array.isArray(openedParts.partNumbers)
  ? openedParts.partNumbers
  : [];

function hasParts(required) {
  return required.every(p => partNumbers.indexOf(p) !== -1);
}

// CP1: Correct series (most popular Web App Security) was opened
const cp1Passed = !!(topSeries && seriesOpened && seriesOpened.seriesId === topSeries.id);
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// CP2: Instrumentation shows part 1 of that series was opened
const cp2Passed = !!(topSeries && openedParts && openedParts.seriesId === topSeries.id && hasParts([1]));
checkpoints.push({ passed: cp2Passed, weight: 0.2 });

// CP3: Parts 1–3 of that series were opened
const cp3Passed = !!(topSeries && openedParts && openedParts.seriesId === topSeries.id && hasParts([1, 2, 3]));
checkpoints.push({ passed: cp3Passed, weight: 0.2 });

// CP4: Parts 1–4 of that series were opened
const cp4Passed = !!(topSeries && openedParts && openedParts.seriesId === topSeries.id && hasParts([1, 2, 3, 4]));
checkpoints.push({ passed: cp4Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load data
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const feedbackReasons = JSON.parse(localStorage.getItem('feedback_reasons') || '[]');
const articleFeedback = JSON.parse(localStorage.getItem('article_feedback') || '[]');
const reasonSelections = JSON.parse(localStorage.getItem('article_feedback_reason_selections') || '[]');

// Determine top Tools article by highest average_rating (matching BusinessLogic sort)
const toolsArticles = articles.filter(a => a && a.category_id === 'tools');
toolsArticles.sort((a, b) => {
  const aa = typeof a.average_rating === 'number' ? a.average_rating : 0;
  const ab = typeof b.average_rating === 'number' ? b.average_rating : 0;
  if (ab !== aa) return ab - aa;
  const ra = typeof a.rating_count === 'number' ? a.rating_count : 0;
  const rb = typeof b.rating_count === 'number' ? b.rating_count : 0;
  if (rb !== ra) return rb - ra;
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return db - da;
});

const targetArticle = toolsArticles.length > 0 ? toolsArticles[0] : null;

const allowedReasonCodes = feedbackReasons.map(r => r.code).filter(c => !!c);

let rating4Feedback = [];
let rating4WithLongComment = [];
let rating4LongWithReasons = [];

if (targetArticle) {
  const fbForTarget = articleFeedback.filter(f => f && f.article_id === targetArticle.id);

  rating4Feedback = fbForTarget.filter(f => f.rating_stars === 4);

  rating4WithLongComment = rating4Feedback.filter(f => {
    const text = f.comment || '';
    return text.length >= 20;
  });

  rating4LongWithReasons = rating4WithLongComment.filter(f => {
    const reasons = reasonSelections.filter(rs => rs && rs.article_feedback_id === f.id && allowedReasonCodes.indexOf(rs.reason_code) !== -1);
    const uniqueCodes = new Set(reasons.map(r => r.reason_code));
    return uniqueCodes.size >= 2;
  });
}

// CP1: Top Tools article has at least one 4-star feedback from the user
const cp1Passed = !!(targetArticle && rating4Feedback.length >= 1);
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// CP2: At least one 4-star feedback for that article includes a written comment of >=20 characters
const cp2Passed = !!(targetArticle && rating4WithLongComment.length >= 1);
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3: At least one such 4-star, long-comment feedback also has >=2 valid feedback reasons selected
const cp3Passed = !!(targetArticle && rating4LongWithReasons.length >= 1);
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
